/* ---- Web fonts (loaded via @font-face — survives constructable stylesheets) ---- */
@font-face {
  font-family: 'DM Serif Display';
  src: url('https://cdn.jsdelivr.net/npm/@fontsource/dm-serif-display/files/dm-serif-display-latin-400-normal.woff2') format('woff2');
  font-weight: 400;
  font-display: swap;
}
@font-face {
  font-family: 'Outfit';
  src: url('https://cdn.jsdelivr.net/npm/@fontsource/outfit/files/outfit-latin-400-normal.woff2') format('woff2');
  font-weight: 400;
  font-display: swap;
}
@font-face {
  font-family: 'Outfit';
  src: url('https://cdn.jsdelivr.net/npm/@fontsource/outfit/files/outfit-latin-600-normal.woff2') format('woff2');
  font-weight: 600;
  font-display: swap;
}

:root {
  --colbg1: #f7f5f0;
  --colbg2: #ffffff;
  --colbg3: #f2efe8;
  --colbgi: #ffffff;
  --colfg:  #1c1a17;
  --colfgi: #1c1a17;
  --col0:   #e7e2d8;
  --col1:   #8a8478;
  --col3:   #efe9dc;
  --col4:   #e2ddd2;
  --col6:   #b5462f;
  --notify-rgba: 181, 70, 47;
  --rad1: 6px;
  --rad2: 6px;
  --rad3: 6px;
  --rad4: 6px;
}

* {
  font-family: 'Outfit', system-ui, sans-serif;
}

body {
  background: var(--colbg1);
}

/* Header → clean hairline bar, search in the middle, buttons to the right */
div#header {
  background: transparent;
  border: none;
  border-bottom: 1px solid #e0dacb;
  box-shadow: none;
  border-radius: 0;
  padding: 16px 28px;
  align-items: center;
}
#header-col1 { order: 0; }
#header-col3, #header .col3 { order: 1; flex: 1 1 auto; flex-basis: auto; }
#header-col2 { order: 2; flex: 0 0 auto; }

#site-title h1 {
  font-family: 'DM Serif Display', serif;
  font-weight: 400;
  font-size: 1.7rem;
  letter-spacing: 0.2px;
  color: #1c1a17;
}

button.icon { fill: #1c1a17; }

#search {
  width: 100%;
  border: 1px solid #ddd6c6;
  border-radius: 999px;
  padding: 7px 18px;
  background: #fff;
  font-size: 1rem;
}

/* Centered reading column */
#visible-tiddlers { max-width: 820px; margin: 0 auto; width: 100%; }

div.tiddler {
  background: #fff;
  outline: none;
  border: 1px solid #ece6da;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.04);
  border-radius: 8px;
  padding: 2.6rem 3rem;
}
div.tiddler div.title {
  font-family: 'DM Serif Display', serif;
  font-weight: 400;
  font-size: 2.5rem;
  color: #1c1a17;
  background: transparent;
  letter-spacing: 0.3px;
}
h1, h2, h3, h4 {
  font-family: 'DM Serif Display', serif;
  font-weight: 400;
  color: #2a2722;
}
a:not([class]) { color: #b5462f; }
blockquote { background: #f5f1e8; border-left: 5px solid #b5462f; font-style: italic; }
```

